// src/constants.js
export const CONTRACT_ADDRESS = "0xf543802cD2211B0f2aE4fC008Ea52d37e926a1b4"; // paste from Remix

export const CONTRACT_ABI = [
  {
    "inputs": [],
    "stateMutability": "nonpayable",
    "type": "constructor"
  },
  {
    "inputs": [],
    "name": "owner",
    "outputs": [{ "internalType": "address", "name": "", "type": "address" }],
    "stateMutability": "view",
    "type": "function"
  },
  {
    "inputs": [{ "internalType": "address", "name": "issuer", "type": "address" }],
    "name": "addIssuer",
    "outputs": [],
    "stateMutability": "nonpayable",
    "type": "function"
  },
  {
    "inputs": [{ "internalType": "address", "name": "issuer", "type": "address" }],
    "name": "removeIssuer",
    "outputs": [],
    "stateMutability": "nonpayable",
    "type": "function"
  },
  {
    "inputs": [],
    "name": "isIssuer",
    "outputs": [
      {
        "internalType": "mapping(address => bool)",
        "name": "",
        "type": "mapping"
      }
    ],
    "stateMutability": "view",
    "type": "function"
  }
];
